import{_ as i,o as a,c as e,a as o}from"./chunks/framework.BHSVNLI7.js";const k=JSON.parse('{"title":"用 BusyBox 构建最小根文件系统","description":"","frontmatter":{"title":"用 BusyBox 构建最小根文件系统","prerequisites":["kernel-build"],"next":["qemu-first-boot"],"difficulty":"beginner","tags":["busybox","rootfs","initramfs","cpio","arm64"],"architectures":["arm64"],"kernel_version":"6.19"},"headers":[],"relativePath":"tutorials/foundations/busybox-rootfs.md","filePath":"tutorials/foundations/busybox-rootfs.md","lastUpdated":null}'),t={name:"tutorials/foundations/busybox-rootfs.md"};function n(l,s,d,r,p,c){return a(),e("div",null,[...s[0]||(s[0]=[o(`<h2 id="做什么" tabindex="-1">做什么 <a class="header-anchor" href="#做什么" aria-label="Permalink to &quot;做什么&quot;">​</a></h2><p>内核编译好了，但光有内核是没法用的——内核启动后需要一个根文件系统（rootfs）来提供基本的用户态环境，至少得有个 shell 让我们敲命令吧。这篇我们用 BusyBox 构建一个最小的 rootfs，把它打包成 cpio.gz 格式的 initramfs 镜像，作为内核启动时的初始内存盘。完成之后我们就有了启动所需的全部材料：一颗编译好的内核 + 一个打包好的根文件系统。</p><h2 id="要了解什么" tabindex="-1">要了解什么 <a class="header-anchor" href="#要了解什么" aria-label="Permalink to &quot;要了解什么&quot;">​</a></h2><h3 id="为什么是-busybox" tabindex="-1">为什么是 BusyBox <a class="header-anchor" href="#为什么是-busybox" aria-label="Permalink to &quot;为什么是 BusyBox&quot;">​</a></h3><p>BusyBox 是嵌入式 Linux 世界的瑞士军刀——它把 <code>ls</code>、<code>cat</code>、<code>sh</code>、<code>mount</code>、<code>cp</code>、<code>mv</code> 等几十个标准 Linux 工具打包成一个单一的二进制文件，通过符号链接的方式让每个&quot;命令&quot;都指向同一个 busybox 可执行文件。这样做的好处是极大地节省了存储空间，整个用户态工具集只需要几百 KB，非常适合 initramfs 这种容量敏感的场景。</p><p>我们的 rootfs 不需要是一个功能完备的 Linux 发行版，它只需要做到一件事：启动之后给我们一个可以交互的 shell，让我们能跑 <code>uname -a</code>、<code>cat /proc/cpuinfo</code>、<code>ls /sys/</code> 这些基本命令来验证内核功能。BusyBox 完全满足这个需求。</p><p>（插一个小广告：笔者自己Vibe Coding过一个类似BusyBox的最小core-binutils，叫CFBox，Github这边请：<a href="https://github.com/Awesome-Embedded-Learning-Studio/CFBox%EF%BC%89" target="_blank" rel="noreferrer">https://github.com/Awesome-Embedded-Learning-Studio/CFBox）</a></p><h3 id="构建-rootfs" tabindex="-1">构建 rootfs <a class="header-anchor" href="#构建-rootfs" aria-label="Permalink to &quot;构建 rootfs&quot;">​</a></h3><p>项目提供了一个自动化脚本 <a href="./scripts/rootfs-minimal-maker.sh">rootfs-minimal-maker.sh</a> 来处理整个 rootfs 构建流程。它的核心工作包括：编译 BusyBox（静态链接）、创建 rootfs 目录结构（<code>bin/</code>、<code>sbin/</code>、<code>usr/</code>、<code>proc/</code>、<code>sys/</code>、<code>dev/</code> 等）、安装 BusyBox 的符号链接、生成 <code>/init</code> 启动脚本。运行方式是：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ARCH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">aarch64</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ./scripts/rootfs-minimal-maker.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> defconfig</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这里 <code>ARCH=aarch64</code> 很重要，它决定了编译出来的 BusyBox 是 ARM64 版本的。如果忘了设 <code>ARCH</code>，脚本不会报错，但会把 rootfs 输出到一个路径异常的目录（<code>out/build_latest_/rootfs/</code>——注意那个空的下划线，就是因为 <code>ARCH</code> 为空导致的），而且编译出来的 BusyBox 可能是 x86 架构的。这个坑我们实际踩过，排查起来还挺隐蔽的。</p><p>构建完成后检查一下 rootfs 目录：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/build_latest_arm64/rootfs/</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># bin/  dev/  etc/  init*  proc/  sbin/  sys/  usr/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>一个能启动的最小 rootfs 需要这些目录和文件。<code>bin/</code> 和 <code>sbin/</code> 下面是 BusyBox 的符号链接，<code>init</code> 是内核启动后执行的第一个用户态程序。</p><h3 id="init-内核启动后的第一个用户态程序" tabindex="-1">/init：内核启动后的第一个用户态程序 <a class="header-anchor" href="#init-内核启动后的第一个用户态程序" aria-label="Permalink to &quot;/init：内核启动后的第一个用户态程序&quot;">​</a></h3><p>内核在完成硬件初始化之后，会去执行根文件系统里的 <code>/init</code> 程序（如果内核命令行指定了 <code>rdinit=/init</code> 的话）。我们的 <code>/init</code> 是一个简单的 shell 脚本，做的事情很直白：挂载 <code>/proc</code>、<code>/sys</code>、<code>/dev</code>（devtmpfs），然后启动一个交互式 shell。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#!/bin/sh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mount</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> proc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> proc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mount</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sysfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sysfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mount</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devtmpfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devtmpfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /bin/sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这里每一行都有它的必要性。<code>/proc</code> 提供进程信息和内核参数接口，<code>/sys</code> 提供设备模型和驱动信息，<code>/dev</code> 提供设备节点（比如 <code>/dev/console</code>、<code>/dev/null</code> 等）。如果忘了挂载 <code>/dev</code>， BusyBox 的 shell 启动时会抱怨 <code>can&#39;t access tty</code>，虽然 shell 还是能起来，但会少一些功能（比如 job control）。</p><h3 id="打包成-cpio-gz" tabindex="-1">打包成 cpio.gz <a class="header-anchor" href="#打包成-cpio-gz" aria-label="Permalink to &quot;打包成 cpio.gz&quot;">​</a></h3><p>QEMU 需要的 initrd 镜像是 cpio 格式的归档文件，而且必须是 <code>newc</code> 格式——这是内核 initramfs 的标准格式。我们的构建脚本已经内置了打包步骤，但如果你需要手动打包（比如修改了 rootfs 内容），命令如下：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/build_latest_arm64/rootfs</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -print0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> cpio</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --null</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ov</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --format=newc</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/dev/null</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> gzip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -9</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../rootfs.cpio.gz</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>拆解一下这条管道命令：<code>find . -print0</code> 递归列出 rootfs 下所有文件，用 null 字节分隔（处理文件名中的空格和特殊字符）；<code>cpio --null -ov --format=newc</code> 读取这些路径，打包成 newc 格式的 cpio 归档；<code>gzip -9</code> 用最大压缩比压缩，最终产出一个大约 1MB 的 <code>rootfs.cpio.gz</code> 文件。</p><p>为什么用静态链接？BusyBox 编译时我们选择了静态链接（<code>CONFIG_STATIC=y</code>），这意味着 BusyBox 的可执行文件包含了所有需要的 C 库函数，不依赖任何外部共享库（<code>.so</code> 文件）。在 initramfs 场景下这是必要的，因为我们的 rootfs 里没有 <code>/lib/</code> 目录——如果 BusyBox 是动态链接的，内核启动后执行 <code>/init</code> 时会找不到动态链接器（<code>ld-linux-aarch64.so.1</code>），直接报错退出。</p><h2 id="动手试试" tabindex="-1">动手试试 <a class="header-anchor" href="#动手试试" aria-label="Permalink to &quot;动手试试&quot;">​</a></h2><ol><li>运行 <code>ARCH=aarch64 ./scripts/rootfs-minimal-maker.sh defconfig</code> 构建 rootfs</li><li>检查 <code>out/build_latest_arm64/rootfs/init</code> 文件是否存在且有执行权限（<code>ls -l</code>）</li><li>用 <code>file out/build_latest_arm64/rootfs/bin/busybox</code> 确认 BusyBox 是 ARM64 架构的静态链接二进制</li><li>检查 <code>out/build_latest_arm64/rootfs.cpio.gz</code> 是否已生成，用 <code>ls -lh</code> 查看大小</li></ol><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><a href="./scripts/rootfs-minimal-maker.sh">rootfs-minimal-maker.sh</a> — rootfs 构建脚本，特别是 <code>setup_rootfs()</code> 函数展示了最小 rootfs 需要哪些目录和文件</li><li><a href="https://busybox.net/" target="_blank" rel="noreferrer">BusyBox 官方网站</a> — BusyBox 项目主页和文档</li></ul>`,27)])])}const u=i(t,[["render",n]]);export{k as __pageData,u as default};
